commands.cmd:
python3 -c "
import pathlib, sys

mlruns = pathlib.Path('mlruns')
run_ids = {}
for meta in mlruns.rglob('meta.yaml'):
    content = meta.read_text()
    for line in content.splitlines():
        if line.startswith('run_id:'):
            run_id = line.split(':', 1)[1].strip()
            if run_id in run_ids:
                print(f'COLLISION: run_id={run_id} in {meta} AND {run_ids[run_id]}')
                sys.exit(1)
            run_ids[run_id] = str(meta)
print(f'OK: {len(run_ids)} unique run IDs in merged mlruns — no collision')
"
